// src/pages/ManageCourse.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';
import axios from 'axios';
import PriceEditor from '../../components/courses/PriceEditor';
// ─── helpers ──────────────────────────────────────────────────────────────────
const newLectureForm = () => ({
  localId: Date.now() + Math.random(),
  title: '',
  description: '',
  video_type: 'upload',
  video_url: '',
  file: null,
  s3_key: '',
  duration_minutes: 0,
  is_free_preview: false,
  uploadStatus: '',
  uploadProgress: 0,
});

// ─── LectureForm – إضافة ليكتشر جديد على section موجود ──────────────────────
const LectureForm = ({ sectionId, lectureCount, onSaved }) => {
  const [open, setOpen]   = useState(false);
  const [lec, setLec]     = useState(newLectureForm());
  const [saving, setSaving] = useState(false);
  const [err, setErr]     = useState('');

  const update = (field, value) => setLec((prev) => ({ ...prev, [field]: value }));

  const uploadToS3 = async (file) => {
    update('uploadStatus', 'uploading');
    update('uploadProgress', 0);
    try {
      const { data } = await api.post('/courses/lectures/presigned-upload/', {
        file_name: file.name, file_type: file.type,
      });
      await axios.put(data.upload_url, file, {
        headers: { 'Content-Type': file.type },
        onUploadProgress: (e) =>
          update('uploadProgress', Math.round((e.loaded / e.total) * 100)),
      });
      update('s3_key', data.s3_key);
      update('uploadStatus', 'done');
    } catch {
      update('uploadStatus', 'error');
    }
  };

  const handleSave = async () => {
    setErr('');
    if (!lec.title.trim()) { setErr('عنوان الليكتشر مطلوب'); return; }
    if (lec.video_type === 'upload' && !lec.s3_key) { setErr('ارفع الفيديو على S3 الأول'); return; }
    if (lec.video_type !== 'upload' && !lec.video_url) { setErr('الرابط مطلوب'); return; }

    setSaving(true);
    try {
      await api.post('/courses/lectures/', {
        section: sectionId,
        title: lec.title,
        description: lec.description,
        video_type: lec.video_type,
        video_url: lec.video_type !== 'upload' ? lec.video_url : '',
        s3_key: lec.video_type === 'upload' ? lec.s3_key : '',
        duration_minutes: lec.duration_minutes,
        order: lectureCount,
        is_free_preview: lec.is_free_preview,
      });
      setLec(newLectureForm());
      setOpen(false);
      onSaved();
    } catch (e) {
      setErr('فشل الحفظ: ' + (e.response?.data?.detail || e.message));
    } finally {
      setSaving(false);
    }
  };

  if (!open) return (
    <button style={s.btnAddLec} onClick={() => setOpen(true)}>+ إضافة ليكتشر</button>
  );

  return (
    <div style={s.lecForm}>
      <div style={s.rowBetween}>
        <strong style={{ fontSize: 14 }}>ليكتشر جديد</strong>
        <button style={s.btnClose} onClick={() => { setOpen(false); setLec(newLectureForm()); }}>✕</button>
      </div>

      <label style={s.label}>عنوان الليكتشر *</label>
      <input style={s.input} value={lec.title} placeholder="مثال: مقدمة عن الوحدة"
        onChange={(e) => update('title', e.target.value)} />

      <label style={s.label}>نوع المحتوى</label>
      <select style={s.input} value={lec.video_type}
        onChange={(e) => update('video_type', e.target.value)}>
        <option value="upload">🎬 رفع فيديو على S3</option>
        <option value="youtube">▶ رابط YouTube</option>
        <option value="vimeo">▶ رابط Vimeo</option>
      </select>

      {lec.video_type === 'upload' ? (
        <div style={s.uploadBox}>
          {lec.uploadStatus !== 'done' && (
            <>
              <label style={s.label}>📁 اختر ملف الفيديو</label>
              <input type="file" accept="video/mp4,video/webm,video/quicktime"
                onChange={(e) => { const f = e.target.files[0]; if (f) update('file', f); }} />
              {lec.file && (
                <div style={s.fileInfo}>
                  <span>📹 {lec.file.name}</span>
                  <span style={{ color:'#666', fontSize:12 }}>{(lec.file.size/1024/1024).toFixed(1)} MB</span>
                </div>
              )}
              {lec.file && lec.uploadStatus === '' && (
                <button style={s.btnUpload} onClick={() => uploadToS3(lec.file)}>⬆ ارفع على S3</button>
              )}
            </>
          )}
          {lec.uploadStatus === 'uploading' && (
            <div style={{ marginTop:8 }}>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:13, marginBottom:4 }}>
                <span>⏳ جاري الرفع...</span><span>{lec.uploadProgress}%</span>
              </div>
              <div style={s.progressWrap}><div style={{ ...s.progressBar, width:`${lec.uploadProgress}%` }} /></div>
            </div>
          )}
          {lec.uploadStatus === 'done' && (
            <div style={s.uploadDone}>
              <span>✅ تم الرفع بنجاح</span>
              <button style={s.btnSmGray} onClick={() => { update('file',null); update('s3_key',''); update('uploadStatus',''); }}>🔄 تغيير</button>
            </div>
          )}
          {lec.uploadStatus === 'error' && (
            <><p style={{ color:'#dc3545', fontSize:13 }}>❌ فشل الرفع</p>
            <button style={s.btnUpload} onClick={() => uploadToS3(lec.file)}>🔄 إعادة</button></>
          )}
        </div>
      ) : (
        <div>
          <label style={s.label}>{lec.video_type === 'youtube' ? '▶ رابط YouTube' : '▶ رابط Vimeo'}</label>
          <input style={s.input} type="url"
            placeholder={lec.video_type === 'youtube' ? 'https://www.youtube.com/watch?v=...' : 'https://vimeo.com/...'}
            value={lec.video_url} onChange={(e) => update('video_url', e.target.value)} />
        </div>
      )}

      <div style={{ display:'flex', gap:16, marginTop:8, alignItems:'flex-end' }}>
        <div>
          <label style={s.label}>المدة (دقيقة)</label>
          <input style={{ ...s.input, width:90 }} type="number" min="0"
            value={lec.duration_minutes} onChange={(e) => update('duration_minutes', +e.target.value)} />
        </div>
        <label style={{ cursor:'pointer', fontSize:14, paddingBottom:8 }}>
          <input type="checkbox" checked={lec.is_free_preview}
            onChange={(e) => update('is_free_preview', e.target.checked)} />
          {' '}معاينة مجانية
        </label>
      </div>

      {err && <p style={{ color:'#dc3545', fontSize:13, marginTop:8 }}>⚠ {err}</p>}

      <div style={{ display:'flex', gap:8, marginTop:12 }}>
        <button style={s.btnSaveLec} onClick={handleSave} disabled={saving}>
          {saving ? '⏳...' : '💾 حفظ الليكتشر'}
        </button>
        <button style={s.btnCancelLec} onClick={() => { setOpen(false); setLec(newLectureForm()); }}>إلغاء</button>
      </div>
    </div>
  );
};

// ─── AddSectionForm ───────────────────────────────────────────────────────────
const AddSectionForm = ({ courseId, sectionCount, onSaved }) => {
  const [open, setOpen]     = useState(false);
  const [title, setTitle]   = useState('');
  const [desc, setDesc]     = useState('');
  const [saving, setSaving] = useState(false);
  const [err, setErr]       = useState('');

  const handleSave = async () => {
    if (!title.trim()) { setErr('عنوان القسم مطلوب'); return; }
    setSaving(true);
    try {
      await api.post('/courses/sections/', {
        course: courseId, title, description: desc, order: sectionCount,
      });
      setTitle(''); setDesc(''); setOpen(false);
      onSaved();
    } catch (e) {
      setErr('فشل الحفظ: ' + (e.response?.data?.detail || e.message));
    } finally { setSaving(false); }
  };

  if (!open) return (
    <button style={s.btnAddSec} onClick={() => setOpen(true)}>+ إضافة قسم جديد</button>
  );

  return (
    <div style={s.secForm}>
      <div style={s.rowBetween}>
        <strong>قسم جديد</strong>
        <button style={s.btnClose} onClick={() => setOpen(false)}>✕</button>
      </div>
      <label style={s.label}>عنوان القسم *</label>
      <input style={s.input} value={title} placeholder="مثال: الوحدة الأولى"
        onChange={(e) => setTitle(e.target.value)} />
      <label style={s.label}>الوصف (اختياري)</label>
      <input style={s.input} value={desc} onChange={(e) => setDesc(e.target.value)} />
      {err && <p style={{ color:'#dc3545', fontSize:13 }}>⚠ {err}</p>}
      <div style={{ display:'flex', gap:8, marginTop:10 }}>
        <button style={s.btnSaveLec} onClick={handleSave} disabled={saving}>
          {saving ? '⏳...' : '💾 حفظ القسم'}
        </button>
        <button style={s.btnCancelLec} onClick={() => setOpen(false)}>إلغاء</button>
      </div>
    </div>
  );
};

// ─── Main Page ────────────────────────────────────────────────────────────────
const ManageCourse = () => {
  const { id: courseId } = useParams();
  const navigate = useNavigate();
  const [course, setCourse]   = useState(null);
  const [loading, setLoading] = useState(true);
  const [errMsg, setErrMsg]   = useState('');

  const loadCourse = useCallback(async () => {
    setLoading(true);
    try {
      const res = await api.get(`/courses/${courseId}/`);
      setCourse(res.data);
    } catch { setErrMsg('تعذّر تحميل الكورس'); }
    finally { setLoading(false); }
  }, [courseId]);

  useEffect(() => { loadCourse(); }, [loadCourse]);

  if (loading) return <div style={s.center}>⏳ جاري التحميل...</div>;
  if (!course)  return <div style={s.center}>❌ {errMsg}</div>;

  const sections = course.sections || [];

  return (
    <div style={s.page}>
      <div style={s.container}>

        {/* Header */}
        <div style={s.header}>
          <div>
            <button style={s.btnBack} onClick={() => navigate(-1)}>← رجوع</button>
            <h2 style={{ margin:'6px 0 4px' }}>⚙ إدارة محتوى الكورس</h2>
            <p style={{ color:'#555', margin:0 }}>📚 {course.title}</p>
            <div style={{ display:'flex', gap:8, marginTop:6 }}>
              <span style={s.chip(course.is_approved)}>{course.is_approved ? '✓ معتمد' : '⏳ انتظار موافقة'}</span>
              <span style={s.chip(course.is_published)}>{course.is_published ? '🌐 منشور' : '🔒 غير منشور'}</span>
            </div>
          </div>
        </div>

        {/* Sections */}
        {sections.length === 0 && (
          <div style={s.emptyBox}>
            <p style={{ color:'#aaa', margin:0 }}>لا يوجد أقسام بعد – أضف قسم الأول ⬇</p>
          </div>
        )}

        {sections.map((sec, si) => (
          <div key={sec.id} style={s.sectionCard}>
            {/* Section header */}
            <div style={s.secHeader}>
              <span style={{ fontWeight:700 }}>📂 القسم {si + 1}: {sec.title}</span>
              <span style={{ fontSize:13, color:'#666' }}>{sec.lectures?.length || 0} ليكتشر</span>
            </div>

            {/* Existing lectures */}
            {sec.lectures && sec.lectures.map((lec) => (
              <div key={lec.id} style={s.lecRow}>
                <span style={{ fontSize:15 }}>
                  {lec.video_type === 'upload' ? '🎬' : '▶'}
                </span>
                <span style={{ flex:1 }}>{lec.title}</span>
                {lec.duration_minutes > 0 && (
                  <span style={{ color:'#999', fontSize:12 }}>{lec.duration_minutes} د</span>
                )}
                <span style={s.statusBadge(lec.video_status)}>
                  {lec.video_status === 'approved' ? '✓ معتمد'
                   : lec.video_status === 'rejected' ? '✗ مرفوض' : '⏳ معلق'}
                </span>
              </div>
            ))}

            {/* Add lecture form – مباشرة تحت كل section */}
            <div style={{ padding:'0 12px 12px' }}>
              <LectureForm
                sectionId={sec.id}
                lectureCount={sec.lectures?.length || 0}
                onSaved={loadCourse}
              />
            </div>
          </div>
        ))}

        {/* Add section form */}
        <div style={s.addSecWrap}>
          <AddSectionForm
            courseId={courseId}
            sectionCount={sections.length}
            onSaved={loadCourse}
          />
        </div>

      </div>
    </div>
  );
};

// ─── Styles ───────────────────────────────────────────────────────────────────
const s = {
  page:       { background:'#f4f6f8', minHeight:'100vh', padding:'30px 20px' },
  container:  { maxWidth:780, margin:'0 auto' },
  center:     { textAlign:'center', padding:60, fontSize:18, color:'#666' },
  header:     { background:'#fff', borderRadius:12, padding:20, marginBottom:20,
                boxShadow:'0 2px 12px rgba(0,0,0,0.07)' },
  btnBack:    { background:'none', border:'none', color:'#007bff', cursor:'pointer', fontSize:14, padding:0 },
  chip: (on) => ({
    display:'inline-block', fontSize:12, padding:'3px 10px', borderRadius:20,
    background: on ? '#d4edda' : '#fff3cd', color: on ? '#155724' : '#856404', fontWeight:600,
  }),
  emptyBox:   { background:'#fff', borderRadius:12, padding:30, textAlign:'center',
                marginBottom:16, boxShadow:'0 2px 12px rgba(0,0,0,0.07)' },
  sectionCard:{ background:'#fff', borderRadius:12, marginBottom:16,
                boxShadow:'0 2px 12px rgba(0,0,0,0.07)', overflow:'hidden' },
  secHeader:  { display:'flex', justifyContent:'space-between', alignItems:'center',
                padding:'14px 16px', background:'#f0f4ff', borderBottom:'1px solid #e0e8ff' },
  lecRow:     { display:'flex', alignItems:'center', gap:10, padding:'10px 16px',
                borderBottom:'1px solid #f5f5f5', fontSize:14 },
  statusBadge:(st) => ({
    fontSize:11, padding:'2px 8px', borderRadius:10, fontWeight:600,
    background: st==='approved'?'#d4edda': st==='rejected'?'#f8d7da':'#fff3cd',
    color:      st==='approved'?'#155724': st==='rejected'?'#721c24':'#856404',
  }),
  addSecWrap: { background:'#fff', borderRadius:12, padding:20,
                boxShadow:'0 2px 12px rgba(0,0,0,0.07)' },
  btnAddSec:  { background:'#007bff', color:'#fff', border:'none', borderRadius:8,
                padding:'10px 20px', cursor:'pointer', fontWeight:600, fontSize:14, width:'100%' },
  btnAddLec:  { background:'#f0f4ff', color:'#0066cc', border:'1px solid #c0d4ff',
                borderRadius:6, padding:'8px 16px', cursor:'pointer', fontWeight:600,
                fontSize:13, width:'100%', marginTop:4 },
  lecForm:    { background:'#f8fbff', border:'1px solid #d0e4ff', borderRadius:8,
                padding:14, marginTop:8 },
  secForm:    { background:'#f8fff8', border:'1px solid #c3e6c3', borderRadius:8, padding:14 },
  rowBetween: { display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:10 },
  label:      { display:'block', fontSize:13, fontWeight:500, marginBottom:4, marginTop:8, color:'#444' },
  input:      { width:'100%', padding:'8px 10px', borderRadius:6, border:'1px solid #ccc',
                fontSize:14, boxSizing:'border-box' },
  btnClose:   { background:'none', border:'none', fontSize:18, cursor:'pointer', color:'#999' },
  btnSaveLec: { background:'#28a745', color:'#fff', border:'none', borderRadius:6,
                padding:'8px 18px', cursor:'pointer', fontWeight:600, fontSize:13 },
  btnCancelLec:{ background:'#f0f0f0', color:'#555', border:'none', borderRadius:6,
                 padding:'8px 14px', cursor:'pointer', fontSize:13 },
  uploadBox:  { background:'#f0f7ff', border:'1px dashed #90c2ff', borderRadius:8, padding:12, marginTop:8 },
  fileInfo:   { display:'flex', justifyContent:'space-between', background:'#fff',
                borderRadius:6, padding:'6px 10px', marginTop:6, border:'1px solid #ddd', fontSize:13 },
  btnUpload:  { background:'#0066cc', color:'#fff', border:'none', borderRadius:6,
                padding:'9px 16px', cursor:'pointer', fontSize:13, marginTop:8, width:'100%', fontWeight:600 },
  btnSmGray:  { background:'#6c757d', color:'#fff', border:'none', borderRadius:6,
                padding:'4px 10px', cursor:'pointer', fontSize:12, marginLeft:8 },
  uploadDone: { display:'flex', alignItems:'center', justifyContent:'space-between',
                background:'#d4edda', borderRadius:6, padding:'8px 12px', marginTop:8,
                color:'#155724', fontWeight:500, fontSize:13 },
  progressWrap:{ background:'#e9ecef', borderRadius:6, height:16, overflow:'hidden' },
  progressBar: { background:'#007bff', height:'100%', transition:'width 0.3s' },
};

export default ManageCourse;
